from collections import defaultdict, deque

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    # Build the graph
    graph = defaultdict(list)
    for u, v in connections:
        graph[u].append(v)
        graph[v].append(u)

    # For each node, keep track of its current state (online or offline)
    online = [True] * (c + 1)  # 1-based indexing

    # For each node, keep track of the minimum online node in its connected component
    # We'll use BFS to find the minimum online node in the component
    # We'll use a dictionary to store the minimum online node for each component
    component_min = {}

    # Function to find the minimum online node in the component of a node
    def get_component_min(node):
        if node not in component_min:
            # Perform BFS to find all nodes in the component
            visited = set()
            queue = deque([node])
            visited.add(node)
            while queue:
                current = queue.popleft()
                for neighbor in graph[current]:
                    if neighbor not in visited:
                        visited.add(neighbor)
                        queue.append(neighbor)
            # Now find the minimum online node in this component
            min_node = None
            for n in visited:
                if online[n]:
                    if min_node is None or n < min_node:
                        min_node = n
            component_min[node] = min_node
        return component_min[node]

    result = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if online[x]:
                result.append(x)
            else:
                # Find the minimum online node in the component of x
                min_node = get_component_min(x)
                if min_node is not None:
                    result.append(min_node)
                else:
                    result.append(-1)
        else:
            x = query[1]
            online[x] = False

    return result
